mapper.update:
UPDATE board SET
b_view_count=b_view_count+1 
WHERE b_id=#{b_id}

mapper.select:
SELECT * FROM ( SELECT ROWNUM AS num, A.* FROM ( SELECT board.b_id, b_title, b_thumbnail, ROUND(AVG(b_review_score),1) AS b_review_score, COUNT(DISTINCT b_review_id) AS review_count, MIN(b_op_price) AS b_op_price, u_s_com, b_type, board.b_view_count FROM board JOIN board_option ON board.b_id = board_option.b_id JOIN users_seller ON board.u_s_id = users_seller.u_s_id JOIN review ON board.b_id = review.b_id WHERE (b_title LIKE '%'||#{keyword}||'%' OR b_content LIKE '%'||#{keyword}||'%') GROUP BY board.b_id,b_title,b_thumbnail,u_s_com,b_type,board.b_view_count
ORDER BY b_op_price ASC ORDER BY b_op_price DESC ORDER BY review_count DESC ORDER BY board.b_view_count DESC ORDER BY b_review_score DESC ORDER BY board.b_id DESC
) A ) WHERE num BETWEEN #{start} AND #{end}

SELECT * FROM ( SELECT ROWNUM AS num, A.* FROM ( SELECT board.b_id, b_title, b_thumbnail, ROUND(AVG(b_review_score),1) AS b_review_score, COUNT(DISTINCT b_review_id) AS review_count, MIN(b_op_price) AS b_op_price, u_s_com, b_type, board.b_view_count FROM board JOIN board_option ON board.b_id = board_option.b_id JOIN users_seller ON board.u_s_id = users_seller.u_s_id JOIN review ON board.b_id = review.b_id WHERE b_type = #{b_type} GROUP BY board.b_id,b_title,b_thumbnail,u_s_com,b_type,board.b_view_count
ORDER BY b_op_price ASC ORDER BY b_op_price DESC ORDER BY review_count DESC ORDER BY board.b_view_count DESC ORDER BY b_review_score DESC ORDER BY board.b_id DESC
) A ) WHERE num BETWEEN #{start} AND #{end}

SELECT CEIL(COUNT(*) / 12.0)
FROM board
WHERE b_type = #{b_type}
